#include <iostream>
#include <algorithm>
#include <map>
using namespace std;
map<string,int> mmap;
int main()
{
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        string s;
        cin>>s;
        if(mmap.count(s)==true)
        {
            mmap[s]++;
            cout<<s<<mmap[s]<<endl;
        }
        else
        {
            cout<<"OK"<<endl;
            mmap[s]=0;
        }
    }
}
